import { useEffect, useRef, useState } from 'react';
import { useGameStore } from '../../state/store.js';
import { bus } from '../../lib/bus.js';

// Classic Windows FreeCell win-cascade. Foundations spawn cards (in rank order
// A→K, all 4 suits) that bounce off the bottom of the screen, gravity-style.
//
// Approach: canvas-based for cheap render. ~52 cards × ~60 frames each =
// O(n × frames) work, runs at 60fps via requestAnimationFrame.

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  rank: number;
  suit: 'C' | 'D' | 'H' | 'S';
  spawnedAt: number;
}

const SUITS: Array<Particle['suit']> = ['C', 'D', 'H', 'S'];
const GLYPHS: Record<Particle['suit'], string> = { C: '♣', D: '♦', H: '♥', S: '♠' };
const COLORS_LIGHT: Record<Particle['suit'], string> = {
  C: '#1c1c1e', D: '#dc2626', H: '#dc2626', S: '#1c1c1e',
};
const COLORS_DARK: Record<Particle['suit'], string> = {
  C: '#f2f2f7', D: '#ff453a', H: '#ff453a', S: '#f2f2f7',
};

const CARD_W = 56;
const CARD_H = 78;
const GRAVITY = 0.4;
const ELASTICITY = 0.78;
const HORIZ_DRAG = 0.995;
const PARTICLE_LIFE_MS = 8000;

function rankText(r: number): string {
  if (r === 1) return 'A';
  if (r === 11) return 'J';
  if (r === 12) return 'Q';
  if (r === 13) return 'K';
  return String(r);
}

function drawCard(ctx: CanvasRenderingContext2D, p: Particle, dark: boolean): void {
  const color = dark ? COLORS_DARK[p.suit] : COLORS_LIGHT[p.suit];
  const bg = dark ? '#0c0c0d' : '#ffffff';
  const border = dark ? 'rgba(242,242,247,0.3)' : 'rgba(0,0,0,0.15)';

  // Rounded rect
  ctx.fillStyle = bg;
  ctx.strokeStyle = border;
  ctx.lineWidth = 1;
  const r = 6;
  ctx.beginPath();
  ctx.moveTo(p.x + r, p.y);
  ctx.lineTo(p.x + CARD_W - r, p.y);
  ctx.quadraticCurveTo(p.x + CARD_W, p.y, p.x + CARD_W, p.y + r);
  ctx.lineTo(p.x + CARD_W, p.y + CARD_H - r);
  ctx.quadraticCurveTo(p.x + CARD_W, p.y + CARD_H, p.x + CARD_W - r, p.y + CARD_H);
  ctx.lineTo(p.x + r, p.y + CARD_H);
  ctx.quadraticCurveTo(p.x, p.y + CARD_H, p.x, p.y + CARD_H - r);
  ctx.lineTo(p.x, p.y + r);
  ctx.quadraticCurveTo(p.x, p.y, p.x + r, p.y);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Rank + suit glyph
  ctx.fillStyle = color;
  ctx.font = 'bold 14px system-ui, sans-serif';
  ctx.textBaseline = 'top';
  ctx.fillText(rankText(p.rank), p.x + 4, p.y + 4);
  ctx.font = '12px sans-serif';
  ctx.fillText(GLYPHS[p.suit], p.x + 4, p.y + 18);

  // Center glyph
  ctx.font = 'bold 22px sans-serif';
  ctx.textAlign = 'center';
  ctx.fillText(GLYPHS[p.suit], p.x + CARD_W / 2, p.y + CARD_H / 2 - 11);
  ctx.textAlign = 'start';
}

interface WinCascadeProps {
  /** When true, the cascade starts immediately on mount. */
  armed?: boolean;
}

export function WinCascade({ armed = false }: WinCascadeProps) {
  // Start active when the parent lazy-loader has already detected a win.
  // Subsequent wins (replay → win again) re-trigger via the gameWon bus event.
  const [active, setActive] = useState<boolean>(armed);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const rafRef = useRef<number | null>(null);
  const status = useGameStore((s) => s.status);

  useEffect(() => {
    const off = bus.on('gameWon', () => setActive(true));
    return off;
  }, []);

  useEffect(() => {
    if (!active) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const W = window.innerWidth;
    const H = window.innerHeight;
    canvas.width = W;
    canvas.height = H;

    const dark = document.documentElement.dataset.theme === 'dark';

    // Spawn schedule: start near the foundations, push each card outward.
    // O(52) cards total, staggered across ~3 seconds.
    const foundations = document.querySelectorAll<HTMLElement>('.ms-foundation');
    const spawnPoints: Array<{ x: number; y: number }> = [];
    foundations.forEach((el) => {
      const r = el.getBoundingClientRect();
      spawnPoints.push({ x: r.left + r.width / 2 - CARD_W / 2, y: r.top + r.height / 2 - CARD_H / 2 });
    });
    if (spawnPoints.length === 0) {
      // Fallback: top-center
      spawnPoints.push({ x: W / 2 - CARD_W / 2, y: 40 });
    }

    const particles: Particle[] = [];
    const startTime = performance.now();
    let nextSpawnIdx = 0;
    const totalSpawns: Array<{ rank: number; suit: Particle['suit']; spawnAt: number; src: number }> = [];
    // K → A for each suit so the foundation visually empties as cards fly off
    for (let r = 13; r >= 1; r--) {
      for (let sIdx = 0; sIdx < 4; sIdx++) {
        totalSpawns.push({
          rank: r,
          suit: SUITS[sIdx]!,
          spawnAt: (13 - r) * 180 + sIdx * 40,
          src: sIdx,
        });
      }
    }

    function frame() {
      const elapsed = performance.now() - startTime;
      // Spawn new particles whose time has come.
      while (nextSpawnIdx < totalSpawns.length && totalSpawns[nextSpawnIdx]!.spawnAt <= elapsed) {
        const s = totalSpawns[nextSpawnIdx]!;
        const src = spawnPoints[s.src % spawnPoints.length]!;
        // Initial velocity: shoot left or right alternately so cards spread.
        const dir = s.src % 2 === 0 ? -1 : 1;
        particles.push({
          x: src.x,
          y: src.y,
          vx: dir * (3 + Math.random() * 4),
          vy: -(2 + Math.random() * 3),
          rank: s.rank,
          suit: s.suit,
          spawnedAt: elapsed,
        });
        nextSpawnIdx++;
      }

      ctx!.clearRect(0, 0, W, H);

      let alive = false;
      for (const p of particles) {
        const age = elapsed - p.spawnedAt;
        if (age > PARTICLE_LIFE_MS) continue;
        alive = true;

        p.vy += GRAVITY;
        p.vx *= HORIZ_DRAG;
        p.x += p.vx;
        p.y += p.vy;

        // Bounce off bottom
        if (p.y + CARD_H >= H) {
          p.y = H - CARD_H;
          p.vy = -p.vy * ELASTICITY;
          // Reduce horizontal a bit on each bounce
          p.vx *= 0.92;
        }
        // Bounce off sides
        if (p.x < 0) {
          p.x = 0;
          p.vx = -p.vx * 0.7;
        } else if (p.x + CARD_W > W) {
          p.x = W - CARD_W;
          p.vx = -p.vx * 0.7;
        }

        drawCard(ctx!, p, dark);
      }

      if (alive || nextSpawnIdx < totalSpawns.length) {
        rafRef.current = requestAnimationFrame(frame);
      } else {
        setActive(false);
      }
    }

    rafRef.current = requestAnimationFrame(frame);

    // Tap-to-skip
    function skip() {
      setActive(false);
    }
    window.addEventListener('pointerdown', skip, { once: true });
    window.addEventListener('keydown', skip, { once: true });

    return () => {
      if (rafRef.current !== null) cancelAnimationFrame(rafRef.current);
      window.removeEventListener('pointerdown', skip);
      window.removeEventListener('keydown', skip);
    };
  }, [active]);

  // Reset on new game (status change away from 'won').
  useEffect(() => {
    if (status !== 'won') setActive(false);
  }, [status]);

  if (!active) return null;
  return (
    <canvas
      ref={canvasRef}
      className="ce-win-cascade"
      data-testid="cellar-win-cascade"
      aria-hidden
      style={{
        position: 'fixed',
        inset: 0,
        pointerEvents: 'none',
        zIndex: 900,
      }}
    />
  );
}
